struct Worker {
    task: Option<String>,
    completed: Vec<String>,
}

impl Worker {
    fn new() -> Self { Worker { task: None, completed: vec![] } }

    fn assign(&mut self, task: impl Into<String>) {
        self.task = Some(task.into());
    }

    fn complete(&mut self) -> Option<String> {
        // take() moves the value out and leaves None — no clone needed!
        let done = self.task.take();
        if let Some(ref t) = done {
            self.completed.push(t.clone());
        }
        done
    }

    // replace() swaps in a new value and returns the old one:
    fn reassign(&mut self, new_task: String) -> Option<String> {
        self.task.replace(new_task)
    }
}

fn main() {
    let mut w = Worker::new();
    w.assign("build");
    println!("task: {:?}", w.task);
    let done = w.complete();
    println!("done: {:?} task: {:?}", done, w.task);

    w.assign("test");
    let old = w.reassign(String::from("deploy"));
    println!("replaced {:?} with {:?}", old, w.task);
}

